import useCanvasObjects from '../hooks/useCanvasObjects';

function CanvasContainer() {
    const { canvasRef, objects, startDragging, dragging, stopDragging } =
        useCanvasObjects();

    return (
        <div
            className="canvas-container"
            ref={canvasRef}
            onMouseMove={dragging}
            onMouseUp={stopDragging}
            style={{ position: 'relative' }}
        >
            {objects.map((obj) => (
                <div
                    key={obj.id}
                    className="obj"
                    onMouseDown={(e) => startDragging(obj.id, e)}
                    style={{
                        position: 'absolute',
                        left: obj.left,
                        top: obj.top,
                    }}
                />
            ))}
        </div>
    );
}

export default CanvasContainer;
